+func TestValidateProcessTriageConfig(t *testing.T) {
+	tests := []struct {
+		name    string
+		cfg     ProcessTriageConfig
+		wantErr bool
+		errMsg  string
+	}{
+		{
+			name:    "valid default config",
+			cfg:     DefaultProcessTriageConfig(),
+			wantErr: false,
+		},
+		{
+			name: "valid custom config",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				BinaryPath:     "",
+				CheckInterval:  60,
+				IdleThreshold:  300,
+				StuckThreshold: 600,
+				OnStuck:        "kill",
+				UseRanoData:    false,
+			},
+			wantErr: false,
+		},
+		{
+			name: "check_interval too low",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				CheckInterval:  3,
+				IdleThreshold:  300,
+				StuckThreshold: 600,
+				OnStuck:        "alert",
+			},
+			wantErr: true,
+			errMsg:  "check_interval must be at least 5 seconds",
+		},
+		{
+			name: "idle_threshold too low",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				CheckInterval:  30,
+				IdleThreshold:  20,
+				StuckThreshold: 600,
+				OnStuck:        "alert",
+			},
+			wantErr: true,
+			errMsg:  "idle_threshold must be at least 30 seconds",
+		},
+		{
+			name: "stuck_threshold less than idle_threshold",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				CheckInterval:  30,
+				IdleThreshold:  600,
+				StuckThreshold: 300,
+				OnStuck:        "alert",
+			},
+			wantErr: true,
+			errMsg:  "stuck_threshold (300) must be >= idle_threshold (600)",
+		},
+		{
+			name: "invalid on_stuck action",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				CheckInterval:  30,
+				IdleThreshold:  300,
+				StuckThreshold: 600,
+				OnStuck:        "invalid",
+			},
+			wantErr: true,
+			errMsg:  "on_stuck must be 'alert', 'kill', or 'ignore'",
+		},
+		{
+			name: "on_stuck ignore is valid",
+			cfg: ProcessTriageConfig{
+				Enabled:        true,
+				CheckInterval:  30,
+				IdleThreshold:  300,
+				StuckThreshold: 600,
+				OnStuck:        "ignore",
+			},
+			wantErr: false,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			err := ValidateProcessTriageConfig(&tt.cfg)
+			if tt.wantErr {
+				if err == nil {
+					t.Error("Expected error but got nil")
+				} else if tt.errMsg != "" && !strings.Contains(err.Error(), tt.errMsg) {
+					t.Errorf("Expected error containing %q, got %q", tt.errMsg, err.Error())
+				}
+			} else {
+				if err != nil {
+					t.Errorf("Unexpected error: %v", err)
+				}
+			}
+		})
+	}
+}
+
+func TestValidateProcessTriageConfigNil(t *testing.T) {
+	err := ValidateProcessTriageConfig(nil)
+	if err != nil {
+		t.Errorf("Expected nil error for nil config, got %v", err)
